import React, { useState } from 'react';

const AboutPage = () => {
  // Quiz State
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [selectedOptionIndex, setSelectedOptionIndex] = useState(null);
  const [score, setScore] = useState(0);
  const [showResult, setShowResult] = useState(false);
  const [resultMessage, setResultMessage] = useState('');
  const [quizComplete, setQuizComplete] = useState(false);

  const quizData = [
    { question: "What is my favorite burger stall?", options: ["Angels Burger", "Out Box", "Franks", "Minute Burger"], answer: 2 },
    { question: "What is my favorite pet?", options: ["Cat", "Bird", "Snake", "Penguin"], answer: 3 },
    { question: "What is my former position in CCS student body organization?", options: ["Vice Mayor", "Peace Officer", "P.I.O", "Muse"], answer: 0 },
    { question: "What is my favorite color", options: ["Black", "Gray", "Green", "Pink"], answer: 3 },
    { question: "What is my favorite instant noodles", options: ["Lucky Me Pancit canton", "Yakisoba", "Mie Goreng", "Buldak"], answer: 2 },
    { question: "What is my usual ordered coffee", options: ["Americano", "Matcha", "Mocha", "Spanish Latte"], answer: 2 },
    { question: "How many cats do i have", options: ["3", "7", "5", "8"], answer: 1 },
    { question: "Kanino ako pinakamatagal nag move on?", options: ["Harisson", "Dwight", "Mackie", "Lester"], answer: 2 }
  ];

  // Gallery Data Arrays (Para hindi paulit-ulit ang images)
  const personalGallery = ["ed6.png.jpg", "ed7.png.jpg", "ed8.png.jpg", "ed9.png.jpg", "ed10.png.jpg"];
  const personalGallery2 = ["ed18.png.jpg", "ed19.png.jpg", "ed20.png.jpg", "ed21.png.jpg", "ed22.png.jpg"];
  const growthGallery = ["ed11.png.jpg", "ed12.png.jpg", "ed2.png.jpg", "ed13.png.jpg", "ed14.png.jpg"];
  const authenticityGallery = ["ed15.png.jpg", "ed16.png.jpg", "ed17.png.jpg"];
  const extraGallery = ["ed26.png.jpg", "ed27.png.jpg", "ed30.png.jpg", "ed29.png.jpg", "ed28.png.jpg"];
  const finalGallery = ["ed23.png.jpg", "ed24.png.jpg", "ed25.png.jpg"];

  const handleOptionSelect = (index) => {
    if (showResult) return;
    setSelectedOptionIndex(index);
  };

  const handleSubmit = () => {
    if (selectedOptionIndex === null) return;

    const currentData = quizData[currentQuestionIndex];
    if (selectedOptionIndex === currentData.answer) {
      setScore(score + 1);
      setResultMessage('Correct!');
    } else {
      setResultMessage(`Wrong! Correct answer: ${currentData.options[currentData.answer]}`);
    }
    setShowResult(true);

    setTimeout(() => {
      if (currentQuestionIndex + 1 < quizData.length) {
        setCurrentQuestionIndex(currentQuestionIndex + 1);
        setSelectedOptionIndex(null);
        setShowResult(false);
        setResultMessage('');
      } else {
        setQuizComplete(true);
      }
    }, 1500);
  };

  return (
    <main>
      {/* SECTION 1: Personal Gallery */}
      <section className="hero">
        <h1>The Keeper of the Personal Gallery</h1>
        <p>I use the lens as a mirror to catch the light I often forget I carry. These photos are my way of whispering 'I am here' to the world. Each frame is a receipt of my own self-love, proving that I am worthy of being seen, especially by myself.</p>
      </section>

      <section className="preview-grid">
        {personalGallery.map((img, i) => (
          <div className="card" key={i}><img src={`/photos/${img}`} width="175" height="175" alt="Personal 1" /></div>
        ))}
      </section>

      <section className="preview-grid">
        {personalGallery2.map((img, i) => (
          <div className="card" key={i}><img src={`/photos/${img}`} width="175" height="175" alt="Personal 2" /></div>
        ))}
      </section>

      {/* SECTION 2: Growth */}
      <section className="hero">
        <h1>The Curator of Collective Growth</h1>
        <p>I never intended to be the captain of the ship, but I’ve learned to love the rhythm of the waves. Leadership has been my compass, pointing me toward a version of myself I didn’t know existed. My peers and mentors are the stars I navigate by without them, my map would be empty.</p>
      </section>

      <section className="preview-grid">
        {growthGallery.map((img, i) => (
          <div className="card" key={i}><img src={`/photos/${img}`} width="175" height="175" alt="Growth" /></div>
        ))}
      </section>

      {/* SECTION 3: Authenticity */}
      <section className="hero">
        <h1>The Mark of Authenticity</h1>
        <p>I am a collection of the books that moved me, the music that held me, and the interests that woke me up. These aren't just 'things'—they are the chapters that define my character.</p>
      </section>

      <section className="preview-grid">
        {authenticityGallery.map((img, i) => (
          <div className="card" key={i}><img src={`/photos/${img}`} width="350" height="350" alt="Authenticity" /></div>
        ))}
      </section>

      <section className="preview-grid">
        {extraGallery.map((img, i) => (
          <div className="card" key={i}><img src={`/photos/${img}`} width="175" height="175" alt="Extra" /></div>
        ))}
      </section>

      <section className="preview-grid">
        {finalGallery.map((img, i) => (
          <div className="card" key={i}><img src={`/photos/${img}`} width="350" height="350" alt="Final" /></div>
        ))}
      </section>

      {/* QUIZ SECTION */}
      
      <section className="quiz-section">
        <div className="quiz-container">
          {!quizComplete ? (
            <>
              <h2>{quizData[currentQuestionIndex].question}</h2>
              <div className="options">
                {quizData[currentQuestionIndex].options.map((option, index) => (
                  <div
                    key={index}
                    className={`option ${selectedOptionIndex === index ? 'selected' : ''}`}
                    onClick={() => handleOptionSelect(index)}
                  >
                    {option}
                  </div>
                ))}
              </div>
              <button 
                id="submitBtn" 
                onClick={handleSubmit} 
                disabled={selectedOptionIndex === null || showResult}
              >
                Submit Answer
              </button>
              {showResult && (
                <div id="result" style={{ color: resultMessage === 'Correct!' ? 'green' : 'red' }}>
                  {resultMessage}
                </div>
              )}
            </>
          ) : (
            <div className="quiz-container">
              <h2>Quiz Complete!</h2>
              <div id="result">Your final score is {score} out of {quizData.length}.</div>
              <button onClick={() => window.location.reload()} style={{marginTop: '20px'}}>Restart Quiz</button>
            </div>
          )}
        </div>
      </section>

      <footer>
        <p>&copy; Cead. All rights reserved. | Contact: edrickbillones0@gmail.com</p>
      </footer>
    </main>
  );
};

export default AboutPage;
